import{_ as a}from"./chunks/dashboard_01.InoLIzPU.js";import{_ as o,o as r,c as t,a2 as i}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"داشبورد (Dashboard)","description":"","frontmatter":{},"headers":[],"relativePath":"fa/getting-started/dashboard.md","filePath":"fa/getting-started/dashboard.md"}'),l={name:"fa/getting-started/dashboard.md"};function n(s,e,c,d,h,g){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="داشبورد-dashboard" tabindex="-1"><i class="ph ph-speedometer"></i> داشبورد (Dashboard) <a class="header-anchor" href="#داشبورد-dashboard" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-speedometer&quot;&gt;&lt;/i&gt; داشبورد (Dashboard)&quot;">​</a></h1><p><strong>داشبورد</strong> یک پنل کنترل و Profiler قدرتمند درون‌بازی است. این امکان را به شما می‌دهد تا عملکرد افزونه را نظارت کنید، زمان‌بندی فریم‌ها را تحلیل کنید و به‌صورت دستی سطوح Scaler را مستقیماً در خروجی در حال اجرا لغو (Override) کنید.</p><p><img src="'+a+'" alt=""></p><h2 id="نحوه-استفاده" tabindex="-1">نحوه استفاده <a class="header-anchor" href="#نحوه-استفاده" aria-label="Permalink to &quot;نحوه استفاده&quot;">​</a></h2><p>تنها کافیست فایل <code>Dashboard.prefab</code> را بکشید و در هر صحنه‌ای از پروژه خود رها کنید.<br> این Prefab به‌طور خودکار به‌عنوان <code>DontDestroyOnLoad</code> تنظیم می‌شود و در طول انتقال بین صحنه‌ها فعال باقی می‌ماند.</p><div class="info custom-block"><p class="custom-block-title">نکاتی برای نسخه نهایی (Production Build)</p><p>داشبورد کاملاً از هسته افزونه جدا است. قبل از انتشار بازی خود، به‌سادگی این Prefab را از صحنه پاک کنید. سیستم Code Stripping انجین Unity به‌طور خودکار تمام کدهای داشبورد را از نسخه نهایی حذف خواهد کرد (که از حجیم شدن پوشه <code>Resources</code> جلوگیری می‌کند) و وزن پروژه را در حداقل نگه می‌دارد. هسته WebAP همچنان به‌طور نامرئی در پس‌زمینه اجرا خواهد شد.</p></div><h2 id="پنل-سمت-چپ-کنترل‌ها" tabindex="-1"><i class="ph ph-sliders"></i> پنل سمت چپ (کنترل‌ها) <a class="header-anchor" href="#پنل-سمت-چپ-کنترل‌ها" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; پنل سمت چپ (کنترل‌ها)&quot;">​</a></h2><p>سمت چپ داشبورد برای تعامل بلادرنگ با افزونه طراحی شده است.</p><ul><li><strong>Enable Web AP</strong><br> سوئیچ اصلی هسته افزونه. در صورت غیرفعال شدن، بهینه‌سازی خودکار متوقف شده و تمام پارامترهای گرافیکی به مقادیر اصلی (حداکثر) خود بازمی‌گردند.</li><li><strong>Anti Yo-Yo Protection</strong><br> Penalty Lockout را روشن یا خاموش می‌کند. در صورت غیرفعال شدن، افزونه می‌تواند بدون قفل‌های زمانی به‌طور مداوم کیفیت گرافیک را افزایش و کاهش دهد.<br><em>(جزئیات بیشتر: <a href="./../advanced/anti-yoyo">سیستم ضد یویو</a>)</em></li><li><strong>Active Scalers</strong><br> فهرستی از تمام ماژول‌های بهینه‌سازی اضافه‌شده به سیستم. <ul><li><strong>Toggle (سوئیچ):</strong> به‌طور کامل یک Scaler خاص را به‌صورت پویا فعال یا غیرفعال می‌کند.</li><li><strong>Slider (نوار لغزان):</strong> به‌طور دستی سطح کیفیت را نادیده می‌گیرد (<code>Override Level</code>). مقدار <code>0</code> به معنای حداکثر کیفیت است. اگر این نوار را حرکت دهید، Indexer مدیریت این Scaler را متوقف کرده و به شما اجازه می‌دهد تا تأثیر آن را بر بازی خود به‌صورت بصری ارزیابی کنید.</li><li><strong>Resolution Mode (حالت وضوح):</strong> یک تنظیم اختصاصی برای <code>Resolution Scaler</code> (در حالت BiRP). به شما اجازه می‌دهد به‌طور پویا بین استراتژی‌های <code>NativeBrowserScaling</code> و <code>RenderTextureScaling</code> جابجا شوید.<br><em>(جزئیات بیشتر: <a href="./../scalers/reference">مرجع Scalerها</a>)</em></li></ul></li></ul><h2 id="پنل-سمت-راست-تحلیل‌ها" tabindex="-1"><i class="ph ph-chart-bar"></i> پنل سمت راست (تحلیل‌ها) <a class="header-anchor" href="#پنل-سمت-راست-تحلیل‌ها" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-bar&quot;&gt;&lt;/i&gt; پنل سمت راست (تحلیل‌ها)&quot;">​</a></h2><p>سمت راست، متریک‌های خام انجین و منطق داخلی «مغز» افزونه را نمایش می‌دهد. از الگوریتم‌های Zero-GC میانگین متحرک نمایی (Exponential Moving Average) برای صاف کردن نمودارها استفاده می‌شود.</p><h3 id="متریک‌ها-و-زمان‌بندی‌ها-metrics-timings" tabindex="-1">متریک‌ها و زمان‌بندی‌ها (Metrics &amp; Timings) <a class="header-anchor" href="#متریک‌ها-و-زمان‌بندی‌ها-metrics-timings" aria-label="Permalink to &quot;متریک‌ها و زمان‌بندی‌ها (Metrics &amp; Timings)&quot;">​</a></h3><ul><li><strong>Target Min FPS:</strong> هدف پایه عملکرد که از تنظیمات پروژه شما استخراج شده است.</li><li><strong>Current FPS:</strong> نرخ فریم فعلی با نمودار تاریخچه پرش‌ها.</li><li><strong>Current Scale / DPI:</strong> ضریب فعلی وضوح. مقدار <code>1.00</code> نشان‌دهنده وضوح اصلی است. مقادیر پایین‌تر (مثلاً <code>0.50</code>) نشان می‌دهند که جهان 3D برای ذخیره GPU کاهش وضوح داشته است.</li><li><strong>Frame Time / CPU Time:</strong> زمان‌های دقیق سخت‌افزار جمع‌آوری شده از طریق <code>FrameTimingManager</code>. این‌ها کمک می‌کنند تا بفهمید پردازنده چه مقدار زمان واقعی را صرف منطق فریم می‌کند.</li></ul><h3 id="مغز-افزونه-plugin-brain" tabindex="-1">مغز افزونه (Plugin Brain) <a class="header-anchor" href="#مغز-افزونه-plugin-brain" aria-label="Permalink to &quot;مغز افزونه (Plugin Brain)&quot;">​</a></h3><p>منطق خط لوله تصمیم‌گیری را نمایش می‌دهد.<br><em>(جزئیات بیشتر: <a href="./../advanced/how-it-works">چگونه کار می‌کند</a>)</em></p><ul><li><strong>Bottleneck:</strong> تشخیص می‌دهد که در حال حاضر کدام زیرسیستم دستگاه باعث تأخیر می‌شود (<code>CPU</code>، <code>GPU</code>، <code>TargetFrameRate</code> یا <code>Unknown</code>).</li><li><strong>Action:</strong> نشان می‌دهد که Indexer قصد دارد چه کاری انجام دهد (<code>IncreaseQuality</code>، <code>DecreaseQuality</code> یا <code>Stale</code> — اگر هیچ اقدامی لازم نباشد).</li><li><strong>Status (زیر Action):</strong> وضعیت سیستم: <code>Monitoring...</code> (ارزیابی فریم‌ها)، <code>Cooldown</code> (انتظار برای پایداری پس از تغییر گرافیک)، یا <code>Penalty Lockout</code> (جریمه ضد یویو فعال است).</li></ul><h3 id="فعال-active" tabindex="-1">فعال (Active) <a class="header-anchor" href="#فعال-active" aria-label="Permalink to &quot;فعال (Active)&quot;">​</a></h3><ul><li>فهرستی از Scalerهایی که در حال حاضر توسط سیستم برای حفظ عملکرد <strong>کاهش</strong> یافته‌اند. اگر FPS بالا باشد و همه‌چیز بهینه باشد، مقدار <code>- None</code> را نمایش می‌دهد.</li></ul>',18)])])}const b=o(l,[["render",n]]);export{m as __pageData,b as default};
